#include <bits/stdc++.h>
using namespace std;

const int N=12,INF=0x3f3f3f3f;

int n,c[N][N],p[N][N],l[N],g[N][N],f[1<<10][N][N][N][N],ans;
bool used[N];

inline void Update(int &x,int y){
    x=(x<y?x:y);
}

int main(){
    scanf("%d",&n);
    for(int i=0,x;i<n;i++){
        for(int j=0;j<9;j++){
            used[j]=0;
            p[i][j]=N;
        }
        while(~scanf("%d",&x)){
            if(!x)
                break;
            x--;
            if(used[x]){
                puts("-1");
                return 0;
            }
            used[x]=1;
            c[i][l[i]]=x,p[i][x]=l[i];
            l[i]++;
        }
        /*
        if(!l[i]){
            puts("-1");
            return 0;
        }
        */
    }
    for(int i=0;i<n;i++)
        for(int j=0;j<n;j++){
            bool flag=0;
            for(int k=0;k<l[j];k++)
                if(p[i][c[j][k]]==N){
                    flag=1;
                    break;
                }
            if(flag)
                g[i][j]=N;
            else{
                int res=l[i],lst=l[j];
                for(int k=l[i]-1;k>=0;k--){
                    if(p[j][c[i][k]]>lst)
                        break;
                    res=k,lst=p[j][c[i][k]];
                }
                g[i][j]=res;
            }
        }
    for(int i=0;i<n;i++){
        g[n][i]=0;
        g[i][n]=l[i];
    }
    memset(f,0x3f,sizeof(f));
    ans=INF;
    f[0][n][0][n][0]=0;
    for(int i=0;i<n;i++)
        f[1<<i][i][l[i]][n][0]=0;
    for(int S=0;S<1<<n;S++)
        for(int i=0;i<=n;i++)
            for(int L=l[i];L>=0;L--)
                for(int j=0;j<=n;j++)
                    for(int R=0;R<=l[j];R++){
                        int num=f[S][i][L][j][R];
                        if(num==INF)
                            continue;
                        if(L==0 && i!=n){
                            for(int k=0;k<n;k++){
                                if((S>>k)&1)
                                    continue;
                                for(int x=g[k][i];x<=l[k];x++)
                                    Update(f[S|(1<<k)][k][x][j][R],num);
                            }
                        }
                        for(int k=0;k<n;k++){
                            if((S>>k)&1 || R<g[j][k])
                                continue;
                            Update(f[S|(1<<k)][i][L][k][0],num);
                        }
                        for(int k=0;k<9;k++)
                            if((p[i][k]<=L || i==n) && p[j][k]<=R)
                                Update(f[S][i][L-(i<n && p[i][k]==L-1)][j][R+(j<n && p[j][k]==R)],num+1);
                        if(L==0)
                            Update(f[S][n][0][j][R],num);
                        if(S==(1<<n)-1 && L==0 && R==l[j]){
                            //printf("%d %d %d %d %d %d\n",S,i,L,j,R,f[S][i][L][j][R]);
                            Update(ans,num);
                        }
                    }
    printf("%d",(ans==INF?-1:ans));
    return 0;
}
